UPDATE sys_message_receiver
SET is_read   = 1,
    read_time = NOW()
WHERE message_id = #{messageId}
  AND user_id = #{userId}
  AND is_read = 0

UPDATE sys_message_receiver
SET is_deleted = 1
WHERE message_id = #{messageId}
  AND user_id = #{userId}

mapper.select:
SELECT COUNT(*)
FROM sys_message_receiver
WHERE message_id = #{messageId}
  AND user_id = #{userId}

SELECT m.id AS id, m.title AS title, m.content AS content, m.message_type AS messageType, m.priority AS priority, m.sender_type AS senderType, m.sender_id AS senderId, m.create_by AS createBy, m.create_time AS createTime, r.is_read AS isRead, r.read_time AS readTime FROM sys_message_receiver r INNER JOIN sys_message m ON r.message_id = m.id WHERE r.user_id = #{userId} AND r.is_deleted = 0 AND m.status = '1' AND m.deleted = 0
AND m.message_type = #{messageType}
AND r.is_read = #{isRead}
ORDER BY r.is_read ASC, m.create_time DESC LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM sys_message_receiver r
INNER JOIN sys_message m ON r.message_id = m.id
WHERE r.user_id = #{userId} AND r.is_deleted = 0
AND m.status = '1' AND m.deleted = 0

    AND m.message_type = #{messageType}


    AND r.is_read = #{isRead}

SELECT id, message_id, user_id, is_read, read_time, is_deleted
FROM sys_message_receiver
WHERE message_id = #{messageId}
